+            ledger
+                .transition_phase(crate::tx_idempotency::TxPhase::Preparing)
+                .unwrap();
+            ledger
+                .transition_phase(crate::tx_idempotency::TxPhase::Committing)
+                .unwrap();
+            ledger
+                .append(
+                    IdempotencyKey::new(&contract.plan.plan_id.0, "step-0", "commit"),
+                    StepOutcome::Success { result: None },
+                    StepRisk::Low,
+                    "agent-step-0",
+                    1000,
+                )
